Here's a complete example:

**XAML (ItemsPage.xaml)**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.ItemsPage">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding SelectedItem}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate>
                    <Grid Padding="10">
                        <Label Text="{Binding Name}" FontSize="16" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
        </CollectionView>

    </RefreshView>
</ContentPage>
```

**ViewModel (ItemsViewModel.cs)**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> items = new();

    [ObservableProperty]
    private Item? selectedItem;

    [ObservableProperty]
    private bool isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        var data = await _api.GetItemsAsync();
        Items = new ObservableCollection<Item>(data);
        IsRefreshing = false; // stops the refresh spinner
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (SelectedItem is null) return;

        await _nav.NavigateToAsync("DetailPage",
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Binding | Purpose |
|---------|---------|
| `IsRefreshing` → `RefreshView.IsRefreshing` | Controls spinner visibility; set to `false` when load completes |
| `RefreshCommand` → `RefreshView.Command` | Fires when user pulls down |
| `Items` → `CollectionView.ItemsSource` | The data collection |
| `SelectedItem` → `CollectionView.SelectedItem` | Two-way; holds current selection |
| `ItemSelectedCommand` → `SelectionChangedCommand` | Fires on selection change to trigger navigation |

**Important notes:**

1. Set `SelectedItem = null` after navigating so the user can tap the same row again.
2. Set `IsRefreshing = false` at the end of your refresh logic—otherwise the spinner stays visible indefinitely.
3. This uses the **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`). Without them, implement `INotifyPropertyChanged` manually.
